-- PostgreSQL version converted from MySQL dump: df121396-dda1-4172-8121-514bf1a129ae.sql
-- Original database: mugood_things
-- Notes:
-- 1) MySQL AUTO_INCREMENT is converted to GENERATED BY DEFAULT AS IDENTITY.
-- 2) MySQL ON UPDATE CURRENT_TIMESTAMP is implemented with PostgreSQL triggers on updated_at.
-- 3) Foreign keys are added after data import to avoid MySQL dump ordering issues.

SET client_encoding = 'UTF8';
SET standard_conforming_strings = on;

BEGIN;

DROP TABLE IF EXISTS "admin", "banner", "brand", "cart_item", "category", "category_goods_recommend", "goods", "goods_picture", "goods_property", "home_recommend", "order_sku", "orders", "payment", "sku", "sku_spec_value", "spec", "spec_value", "user", "user_address" CASCADE;


-- Table definitions

CREATE TABLE "admin" (
  "id" BIGINT GENERATED BY DEFAULT AS IDENTITY NOT NULL,
  "account" VARCHAR(64) NOT NULL,
  "password_hash" VARCHAR(255) NOT NULL,
  "nickname" VARCHAR(64) DEFAULT NULL,
  "avatar" VARCHAR(512) DEFAULT NULL,
  "mobile" VARCHAR(32) DEFAULT NULL,
  "email" VARCHAR(128) DEFAULT NULL,
  "role" VARCHAR(32) NOT NULL DEFAULT 'admin',
  "status" SMALLINT NOT NULL DEFAULT 1,
  "last_login_at" TIMESTAMP DEFAULT NULL,
  "created_at" TIMESTAMP NOT NULL DEFAULT CURRENT_TIMESTAMP,
  "updated_at" TIMESTAMP NOT NULL DEFAULT CURRENT_TIMESTAMP,
  PRIMARY KEY ("id"),
  CONSTRAINT "uk_admin_account" UNIQUE ("account"),
  CONSTRAINT "uk_admin_mobile" UNIQUE ("mobile")
);

CREATE TABLE "banner" (
  "id" BIGINT GENERATED BY DEFAULT AS IDENTITY NOT NULL,
  "img_url" VARCHAR(512) NOT NULL,
  "href_url" VARCHAR(512) DEFAULT NULL,
  "distribution_site" SMALLINT NOT NULL DEFAULT 1,
  "title" VARCHAR(255) DEFAULT NULL,
  "sort_order" INTEGER NOT NULL DEFAULT 0,
  "status" SMALLINT NOT NULL DEFAULT 1,
  "created_at" TIMESTAMP NOT NULL DEFAULT CURRENT_TIMESTAMP,
  "updated_at" TIMESTAMP NOT NULL DEFAULT CURRENT_TIMESTAMP,
  PRIMARY KEY ("id")
);

CREATE TABLE "brand" (
  "id" BIGINT GENERATED BY DEFAULT AS IDENTITY NOT NULL,
  "name" VARCHAR(128) NOT NULL,
  "logo" VARCHAR(512) DEFAULT NULL,
  "description" VARCHAR(512) DEFAULT NULL,
  "sort_order" INTEGER NOT NULL DEFAULT 0,
  "status" SMALLINT NOT NULL DEFAULT 1,
  "created_at" TIMESTAMP NOT NULL DEFAULT CURRENT_TIMESTAMP,
  "updated_at" TIMESTAMP NOT NULL DEFAULT CURRENT_TIMESTAMP,
  PRIMARY KEY ("id")
);

CREATE TABLE "cart_item" (
  "id" BIGINT GENERATED BY DEFAULT AS IDENTITY NOT NULL,
  "user_id" BIGINT NOT NULL,
  "goods_id" BIGINT NOT NULL,
  "sku_id" BIGINT NOT NULL,
  "count" INTEGER NOT NULL DEFAULT 1,
  "selected" SMALLINT NOT NULL DEFAULT 1,
  "created_at" TIMESTAMP NOT NULL DEFAULT CURRENT_TIMESTAMP,
  "updated_at" TIMESTAMP NOT NULL DEFAULT CURRENT_TIMESTAMP,
  PRIMARY KEY ("id"),
  CONSTRAINT "uk_cart_user_sku" UNIQUE ("user_id","sku_id")
);

CREATE TABLE "category" (
  "id" BIGINT GENERATED BY DEFAULT AS IDENTITY NOT NULL,
  "parent_id" BIGINT DEFAULT NULL,
  "name" VARCHAR(128) NOT NULL,
  "picture" VARCHAR(512) DEFAULT NULL,
  "sale_info" VARCHAR(255) DEFAULT NULL,
  "level" SMALLINT NOT NULL DEFAULT 1,
  "sort_order" INTEGER NOT NULL DEFAULT 0,
  "status" SMALLINT NOT NULL DEFAULT 1,
  "created_at" TIMESTAMP NOT NULL DEFAULT CURRENT_TIMESTAMP,
  "updated_at" TIMESTAMP NOT NULL DEFAULT CURRENT_TIMESTAMP,
  PRIMARY KEY ("id")
);

CREATE TABLE "category_goods_recommend" (
  "id" BIGINT GENERATED BY DEFAULT AS IDENTITY NOT NULL,
  "category_id" BIGINT NOT NULL,
  "goods_id" BIGINT NOT NULL,
  "scene" VARCHAR(32) NOT NULL DEFAULT 'category',
  "sort_order" INTEGER NOT NULL DEFAULT 0,
  PRIMARY KEY ("id"),
  CONSTRAINT "uk_category_goods_scene" UNIQUE ("category_id","goods_id","scene")
);

CREATE TABLE "goods" (
  "id" BIGINT GENERATED BY DEFAULT AS IDENTITY NOT NULL,
  "category_id" BIGINT NOT NULL,
  "brand_id" BIGINT DEFAULT NULL,
  "name" VARCHAR(255) NOT NULL,
  "description" VARCHAR(512) DEFAULT NULL,
  "price" NUMERIC(10,2) NOT NULL DEFAULT 0.00,
  "old_price" NUMERIC(10,2) DEFAULT NULL,
  "main_picture" VARCHAR(512) DEFAULT NULL,
  "sales_count" INTEGER NOT NULL DEFAULT 0,
  "comment_count" INTEGER NOT NULL DEFAULT 0,
  "collect_count" INTEGER NOT NULL DEFAULT 0,
  "order_num" INTEGER NOT NULL DEFAULT 0,
  "evaluate_num" INTEGER NOT NULL DEFAULT 0,
  "inventory" INTEGER NOT NULL DEFAULT 0,
  "is_new" SMALLINT NOT NULL DEFAULT 0,
  "is_hot" SMALLINT NOT NULL DEFAULT 0,
  "publish_time" TIMESTAMP NOT NULL DEFAULT CURRENT_TIMESTAMP,
  "status" SMALLINT NOT NULL DEFAULT 1,
  "created_at" TIMESTAMP NOT NULL DEFAULT CURRENT_TIMESTAMP,
  "updated_at" TIMESTAMP NOT NULL DEFAULT CURRENT_TIMESTAMP,
  PRIMARY KEY ("id")
);

CREATE TABLE "goods_picture" (
  "id" BIGINT GENERATED BY DEFAULT AS IDENTITY NOT NULL,
  "goods_id" BIGINT NOT NULL,
  "picture_url" VARCHAR(512) NOT NULL,
  "picture_type" SMALLINT NOT NULL DEFAULT 1,
  "sort_order" INTEGER NOT NULL DEFAULT 0,
  PRIMARY KEY ("id")
);

CREATE TABLE "goods_property" (
  "id" BIGINT GENERATED BY DEFAULT AS IDENTITY NOT NULL,
  "goods_id" BIGINT NOT NULL,
  "name" VARCHAR(128) NOT NULL,
  "value" VARCHAR(255) NOT NULL,
  "sort_order" INTEGER NOT NULL DEFAULT 0,
  PRIMARY KEY ("id")
);

CREATE TABLE "home_recommend" (
  "id" BIGINT GENERATED BY DEFAULT AS IDENTITY NOT NULL,
  "recommend_type" VARCHAR(32) NOT NULL,
  "title" VARCHAR(128) DEFAULT NULL,
  "alt" VARCHAR(255) DEFAULT NULL,
  "picture" VARCHAR(512) DEFAULT NULL,
  "goods_id" BIGINT DEFAULT NULL,
  "category_id" BIGINT DEFAULT NULL,
  "sort_order" INTEGER NOT NULL DEFAULT 0,
  "status" SMALLINT NOT NULL DEFAULT 1,
  "created_at" TIMESTAMP NOT NULL DEFAULT CURRENT_TIMESTAMP,
  "updated_at" TIMESTAMP NOT NULL DEFAULT CURRENT_TIMESTAMP,
  PRIMARY KEY ("id")
);

CREATE TABLE "order_sku" (
  "id" BIGINT GENERATED BY DEFAULT AS IDENTITY NOT NULL,
  "order_id" BIGINT NOT NULL,
  "goods_id" BIGINT NOT NULL,
  "sku_id" BIGINT NOT NULL,
  "name" VARCHAR(255) NOT NULL,
  "image" VARCHAR(512) DEFAULT NULL,
  "attrs_text" VARCHAR(512) DEFAULT NULL,
  "price" NUMERIC(10,2) NOT NULL DEFAULT 0.00,
  "real_pay" NUMERIC(10,2) NOT NULL DEFAULT 0.00,
  "quantity" INTEGER NOT NULL DEFAULT 1,
  "total_price" NUMERIC(10,2) NOT NULL DEFAULT 0.00,
  "total_pay_price" NUMERIC(10,2) NOT NULL DEFAULT 0.00,
  "created_at" TIMESTAMP NOT NULL DEFAULT CURRENT_TIMESTAMP,
  PRIMARY KEY ("id")
);

CREATE TABLE "orders" (
  "id" BIGINT GENERATED BY DEFAULT AS IDENTITY NOT NULL,
  "order_no" VARCHAR(64) NOT NULL,
  "user_id" BIGINT NOT NULL,
  "address_id" BIGINT DEFAULT NULL,
  "receiver" VARCHAR(64) NOT NULL,
  "contact" VARCHAR(32) NOT NULL,
  "full_location" VARCHAR(255) NOT NULL,
  "address" VARCHAR(255) NOT NULL,
  "goods_count" INTEGER NOT NULL DEFAULT 0,
  "total_price" NUMERIC(10,2) NOT NULL DEFAULT 0.00,
  "post_fee" NUMERIC(10,2) NOT NULL DEFAULT 0.00,
  "total_pay_price" NUMERIC(10,2) NOT NULL DEFAULT 0.00,
  "pay_money" NUMERIC(10,2) NOT NULL DEFAULT 0.00,
  "delivery_time_type" SMALLINT NOT NULL DEFAULT 1,
  "pay_type" SMALLINT NOT NULL DEFAULT 1,
  "pay_channel" SMALLINT NOT NULL DEFAULT 1,
  "buyer_message" VARCHAR(512) DEFAULT NULL,
  "order_state" SMALLINT NOT NULL DEFAULT 1,
  "countdown" INTEGER DEFAULT NULL,
  "pay_deadline" TIMESTAMP DEFAULT NULL,
  "paid_at" TIMESTAMP DEFAULT NULL,
  "shipped_at" TIMESTAMP DEFAULT NULL,
  "received_at" TIMESTAMP DEFAULT NULL,
  "canceled_at" TIMESTAMP DEFAULT NULL,
  "created_at" TIMESTAMP NOT NULL DEFAULT CURRENT_TIMESTAMP,
  "updated_at" TIMESTAMP NOT NULL DEFAULT CURRENT_TIMESTAMP,
  PRIMARY KEY ("id"),
  CONSTRAINT "uk_orders_order_no" UNIQUE ("order_no")
);

CREATE TABLE "payment" (
  "id" BIGINT GENERATED BY DEFAULT AS IDENTITY NOT NULL,
  "order_id" BIGINT NOT NULL,
  "payment_no" VARCHAR(128) DEFAULT NULL,
  "pay_channel" SMALLINT NOT NULL DEFAULT 1,
  "amount" NUMERIC(10,2) NOT NULL DEFAULT 0.00,
  "pay_result" SMALLINT NOT NULL DEFAULT 0,
  "paid_at" TIMESTAMP DEFAULT NULL,
  "callback_payload" JSONB DEFAULT NULL,
  "created_at" TIMESTAMP NOT NULL DEFAULT CURRENT_TIMESTAMP,
  "updated_at" TIMESTAMP NOT NULL DEFAULT CURRENT_TIMESTAMP,
  PRIMARY KEY ("id")
);

CREATE TABLE "sku" (
  "id" BIGINT GENERATED BY DEFAULT AS IDENTITY NOT NULL,
  "goods_id" BIGINT NOT NULL,
  "sku_code" VARCHAR(128) DEFAULT NULL,
  "price" NUMERIC(10,2) NOT NULL DEFAULT 0.00,
  "old_price" NUMERIC(10,2) DEFAULT NULL,
  "inventory" INTEGER NOT NULL DEFAULT 0,
  "picture" VARCHAR(512) DEFAULT NULL,
  "status" SMALLINT NOT NULL DEFAULT 1,
  "created_at" TIMESTAMP NOT NULL DEFAULT CURRENT_TIMESTAMP,
  "updated_at" TIMESTAMP NOT NULL DEFAULT CURRENT_TIMESTAMP,
  PRIMARY KEY ("id"),
  CONSTRAINT "uk_sku_code" UNIQUE ("sku_code")
);

CREATE TABLE "sku_spec_value" (
  "sku_id" BIGINT NOT NULL,
  "spec_id" BIGINT NOT NULL,
  "spec_name" VARCHAR(128) NOT NULL,
  "spec_value_id" BIGINT NOT NULL,
  "value_name" VARCHAR(128) NOT NULL,
  PRIMARY KEY ("sku_id","spec_id")
);

CREATE TABLE "spec" (
  "id" BIGINT GENERATED BY DEFAULT AS IDENTITY NOT NULL,
  "goods_id" BIGINT NOT NULL,
  "name" VARCHAR(128) NOT NULL,
  "sort_order" INTEGER NOT NULL DEFAULT 0,
  PRIMARY KEY ("id")
);

CREATE TABLE "spec_value" (
  "id" BIGINT GENERATED BY DEFAULT AS IDENTITY NOT NULL,
  "spec_id" BIGINT NOT NULL,
  "name" VARCHAR(128) NOT NULL,
  "picture" VARCHAR(512) DEFAULT NULL,
  "sort_order" INTEGER NOT NULL DEFAULT 0,
  PRIMARY KEY ("id")
);

CREATE TABLE "user" (
  "id" BIGINT GENERATED BY DEFAULT AS IDENTITY NOT NULL,
  "account" VARCHAR(64) NOT NULL,
  "password_hash" VARCHAR(255) NOT NULL,
  "nickname" VARCHAR(64) DEFAULT NULL,
  "avatar" VARCHAR(512) DEFAULT NULL,
  "mobile" VARCHAR(32) DEFAULT NULL,
  "email" VARCHAR(128) DEFAULT NULL,
  "gender" SMALLINT NOT NULL DEFAULT 0,
  "status" SMALLINT NOT NULL DEFAULT 1,
  "created_at" TIMESTAMP NOT NULL DEFAULT CURRENT_TIMESTAMP,
  "updated_at" TIMESTAMP NOT NULL DEFAULT CURRENT_TIMESTAMP,
  PRIMARY KEY ("id"),
  CONSTRAINT "uk_user_account" UNIQUE ("account"),
  CONSTRAINT "uk_user_mobile" UNIQUE ("mobile")
);

CREATE TABLE "user_address" (
  "id" BIGINT GENERATED BY DEFAULT AS IDENTITY NOT NULL,
  "user_id" BIGINT NOT NULL,
  "receiver" VARCHAR(64) NOT NULL,
  "contact" VARCHAR(32) NOT NULL,
  "province_code" VARCHAR(32) DEFAULT NULL,
  "city_code" VARCHAR(32) DEFAULT NULL,
  "county_code" VARCHAR(32) DEFAULT NULL,
  "full_location" VARCHAR(255) NOT NULL,
  "address" VARCHAR(255) NOT NULL,
  "postal_code" VARCHAR(32) DEFAULT NULL,
  "is_default" SMALLINT NOT NULL DEFAULT 1,
  "created_at" TIMESTAMP NOT NULL DEFAULT CURRENT_TIMESTAMP,
  "updated_at" TIMESTAMP NOT NULL DEFAULT CURRENT_TIMESTAMP,
  PRIMARY KEY ("id")
);


-- Comments

COMMENT ON TABLE "admin" IS 'Backend administrators';

COMMENT ON COLUMN "admin"."id" IS 'Admin ID';

COMMENT ON COLUMN "admin"."account" IS 'Login account';

COMMENT ON COLUMN "admin"."password_hash" IS 'Password hash or demo password';

COMMENT ON COLUMN "admin"."nickname" IS 'Admin nickname';

COMMENT ON COLUMN "admin"."avatar" IS 'Avatar URL';

COMMENT ON COLUMN "admin"."mobile" IS 'Mobile phone';

COMMENT ON COLUMN "admin"."email" IS 'Email';

COMMENT ON COLUMN "admin"."role" IS 'Role code';

COMMENT ON COLUMN "admin"."status" IS '1 enabled, 0 disabled';

COMMENT ON COLUMN "admin"."last_login_at" IS 'Last login time';

COMMENT ON TABLE "banner" IS 'Home and category banners';

COMMENT ON COLUMN "banner"."img_url" IS 'Banner image URL';

COMMENT ON COLUMN "banner"."href_url" IS 'Click target URL';

COMMENT ON COLUMN "banner"."distribution_site" IS 'Frontend distributionSite';

COMMENT ON TABLE "brand" IS 'Goods brands';

COMMENT ON COLUMN "brand"."id" IS 'Brand ID';

COMMENT ON COLUMN "brand"."name" IS 'Brand name';

COMMENT ON COLUMN "brand"."logo" IS 'Brand logo URL';

COMMENT ON COLUMN "brand"."description" IS 'Brand description';

COMMENT ON TABLE "cart_item" IS 'Shopping cart items';

COMMENT ON COLUMN "cart_item"."selected" IS '1 selected, 0 unselected';

COMMENT ON TABLE "category" IS 'Product categories';

COMMENT ON COLUMN "category"."id" IS 'Category ID';

COMMENT ON COLUMN "category"."parent_id" IS 'Parent category ID';

COMMENT ON COLUMN "category"."name" IS 'Category name';

COMMENT ON COLUMN "category"."picture" IS 'Category image URL';

COMMENT ON COLUMN "category"."sale_info" IS 'Home panel sale text';

COMMENT ON COLUMN "category"."level" IS 'Category level';

COMMENT ON TABLE "category_goods_recommend" IS 'Recommended goods by category or scene';

COMMENT ON COLUMN "category_goods_recommend"."scene" IS 'category, head, relevant, hot24, hotWeek';

COMMENT ON TABLE "goods" IS 'Goods SPU';

COMMENT ON COLUMN "goods"."id" IS 'Goods ID';

COMMENT ON COLUMN "goods"."category_id" IS 'Leaf category ID';

COMMENT ON COLUMN "goods"."brand_id" IS 'Brand ID';

COMMENT ON COLUMN "goods"."name" IS 'Goods name';

COMMENT ON COLUMN "goods"."description" IS 'Short description';

COMMENT ON COLUMN "goods"."price" IS 'Sale price';

COMMENT ON COLUMN "goods"."old_price" IS 'Original price';

COMMENT ON COLUMN "goods"."main_picture" IS 'Primary picture URL';

COMMENT ON COLUMN "goods"."sales_count" IS 'Sales count';

COMMENT ON COLUMN "goods"."comment_count" IS 'Comment count';

COMMENT ON COLUMN "goods"."collect_count" IS 'Collect count';

COMMENT ON COLUMN "goods"."order_num" IS 'Popularity/order metric';

COMMENT ON COLUMN "goods"."evaluate_num" IS 'Evaluate metric';

COMMENT ON COLUMN "goods"."inventory" IS 'Total inventory';

COMMENT ON COLUMN "goods"."is_new" IS 'Shown in home new goods';

COMMENT ON COLUMN "goods"."is_hot" IS 'Shown in hot goods';

COMMENT ON COLUMN "goods"."publish_time" IS 'Publish time';

COMMENT ON COLUMN "goods"."status" IS '1 on sale, 0 off sale';

COMMENT ON TABLE "goods_picture" IS 'Goods carousel and detail pictures';

COMMENT ON COLUMN "goods_picture"."picture_type" IS '1 main carousel, 2 detail picture';

COMMENT ON TABLE "goods_property" IS 'Goods detail properties';

COMMENT ON COLUMN "goods_property"."name" IS 'Property name';

COMMENT ON COLUMN "goods_property"."value" IS 'Property value';

COMMENT ON TABLE "home_recommend" IS 'Home new/hot/product recommendations';

COMMENT ON COLUMN "home_recommend"."recommend_type" IS 'new, hot, product';

COMMENT ON TABLE "order_sku" IS 'Order goods snapshots';

COMMENT ON TABLE "orders" IS 'Member orders';

COMMENT ON COLUMN "orders"."order_no" IS 'Order number shown to user';

COMMENT ON COLUMN "orders"."order_state" IS '1 unpaid, 2 undelivered, 3 unreceived, 4 uncommented, 5 completed, 6 canceled';

COMMENT ON COLUMN "orders"."countdown" IS 'Remaining pay seconds';

COMMENT ON TABLE "payment" IS 'Payment records';

COMMENT ON COLUMN "payment"."payment_no" IS 'External payment number';

COMMENT ON COLUMN "payment"."pay_channel" IS '1 alipay, 2 wechat, 3 bank';

COMMENT ON COLUMN "payment"."pay_result" IS '0 pending, 1 success, 2 failed';

COMMENT ON TABLE "sku" IS 'Goods SKU';

COMMENT ON COLUMN "sku"."sku_code" IS 'SKU code';

COMMENT ON TABLE "sku_spec_value" IS 'SKU selected spec values';

COMMENT ON TABLE "spec" IS 'Goods specification groups';

COMMENT ON COLUMN "spec"."name" IS 'Spec name, such as color or size';

COMMENT ON TABLE "spec_value" IS 'Goods specification values';

COMMENT ON COLUMN "spec_value"."name" IS 'Spec value';

COMMENT ON COLUMN "spec_value"."picture" IS 'Optional picture for value';

COMMENT ON TABLE "user" IS 'Member users';

COMMENT ON COLUMN "user"."id" IS 'User ID';

COMMENT ON COLUMN "user"."account" IS 'Login account';

COMMENT ON COLUMN "user"."password_hash" IS 'Password hash';

COMMENT ON COLUMN "user"."nickname" IS 'Nickname';

COMMENT ON COLUMN "user"."avatar" IS 'Avatar URL';

COMMENT ON COLUMN "user"."mobile" IS 'Mobile phone';

COMMENT ON COLUMN "user"."email" IS 'Email';

COMMENT ON COLUMN "user"."gender" IS '0 unknown, 1 male, 2 female';

COMMENT ON COLUMN "user"."status" IS '1 enabled, 0 disabled';

COMMENT ON TABLE "user_address" IS 'User shipping addresses';

COMMENT ON COLUMN "user_address"."id" IS 'Address ID';

COMMENT ON COLUMN "user_address"."user_id" IS 'User ID';

COMMENT ON COLUMN "user_address"."receiver" IS 'Receiver name';

COMMENT ON COLUMN "user_address"."contact" IS 'Receiver phone';

COMMENT ON COLUMN "user_address"."full_location" IS 'Province city county text';

COMMENT ON COLUMN "user_address"."address" IS 'Detailed address';

COMMENT ON COLUMN "user_address"."is_default" IS '0 default, 1 normal; follows frontend API';


