-- updated_at triggers

CREATE OR REPLACE FUNCTION public.set_updated_at()
RETURNS trigger AS $$
BEGIN
  NEW."updated_at" = CURRENT_TIMESTAMP;
  RETURN NEW;
END;
$$ LANGUAGE plpgsql;

CREATE TRIGGER "trg_admin_updated_at"
BEFORE UPDATE ON "admin"
FOR EACH ROW
EXECUTE FUNCTION public.set_updated_at();

